body.script:
    function cargarXML() {
      const codigo = document.getElementById("codigoINE").value.trim();
      const contenido = document.getElementById("contenido");


      const urlXML = "localidad_" + codigo + ".xml";

      fetch(urlXML)
        .then(response => {
          if (!response.ok) {
            throw new Error("No se pudo cargar el XML. Revisa la ruta o el nombre del archivo.");
          }
          return response.text();
        })
        .then(texto => {
          const parser = new DOMParser();
          const xmlDoc = parser.parseFromString(texto, "application/xml");


          if (xmlDoc.getElementsByTagName("parsererror").length > 0) {
            throw new Error("El XML tiene errores de formato.");
          }

          mostrarDatos(xmlDoc);
        })
        .catch(error => {
          contenido.innerHTML = "
Error: " + error.message + "";
        });
    }

    function mostrarDatos(xmlDoc) {
      const contenido = document.getElementById("contenido");

      const nombre = xmlDoc.getElementsByTagName("nombre")[0].childNodes[0].nodeValue;
      const provincia = xmlDoc.getElementsByTagName("provincia")[0].childNodes[0].nodeValue;

      let html = "
";
      html += "
" + nombre + " (" + provincia + ")";
      html += "";

      const dias = xmlDoc.getElementsByTagName("dia");

      for (let i = 0; i < dias.length; i++) {
        const dia = dias[i];
        const fecha = dia.getAttribute("fecha");

        const tempMax = dia.getElementsByTagName("temperatura")[0].getElementsByTagName("maxima")[0].childNodes[0].nodeValue;
        const tempMin = dia.getElementsByTagName("temperatura")[0].getElementsByTagName("minima")[0].childNodes[0].nodeValue;

        const humedadMax = dia.getElementsByTagName("humedad_relativa")[0].getElementsByTagName("maxima")[0].childNodes[0].nodeValue;
        const humedadMin = dia.getElementsByTagName("humedad_relativa")[0].getElementsByTagName("minima")[0].childNodes[0].nodeValue;

        html += "
";
        html += "
Día " + fecha + "";
        html += "
Temperatura: Máxima " + tempMax + " °C / Mínima " + tempMin + " °C";
        html += "
Humedad relativa: Máxima " + humedadMax + "% / Mínima " + humedadMin + "%";


        html += "
Estado del cielo";
        html += "";
        html += "
PeriodoDescripciónCódigo";

        const cielos = dia.getElementsByTagName("estado_cielo");
        for (let j = 0; j < cielos.length; j++) {
          const cielo = cielos[j];
          const periodo = cielo.getAttribute("periodo") || "Sin periodo";
          const descripcion = cielo.getAttribute("descripcion") || "";
          const codigoCielo = cielo.childNodes[0] ? cielo.childNodes[0].nodeValue : "";
          html += "
";
          html += "" + periodo + "";
          html += "" + descripcion + "";
          html += "" + codigoCielo + "";
          html += "";
        }

        html += "";


        html += "
Viento";
        html += "";
        html += "
PeriodoDirecciónVelocidad";

        const vientos = dia.getElementsByTagName("viento");
        for (let j = 0; j < vientos.length; j++) {
          const viento = vientos[j];
          const periodo = viento.getAttribute("periodo") || "Sin periodo";
          const direccion = viento.getElementsByTagName("direccion")[0].childNodes[0].nodeValue;
          const velocidad = viento.getElementsByTagName("velocidad")[0].childNodes[0].nodeValue;

          html += "
";
          html += "" + periodo + "";
          html += "" + direccion + "";
          html += "" + velocidad + " km/h";
          html += "";
        }

        html += "";
        html += "";
      }

      contenido.innerHTML = html;
    }
